@RestController
@RequestMapping("/api/events")
class EventProducerController {

    private final KafkaProducer<String, String> kafkaProducer;

    public EventProducerController(KafkaProducer<String, String> kafkaProducer) {
        this.kafkaProducer = kafkaProducer;
    }

    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(@RequestBody EventRequest request) {
        try {
            ProducerRecord<String, String> record = createProducerRecord(request);
            RecordMetadata metadata = kafkaProducer.send(record).get();
            
            EventResponse response = new EventResponse(
                "Event published successfully",
                metadata.topic(),
                metadata.partition(),
                metadata.offset(),
                metadata.timestamp()
            );
            
            return ResponseEntity.ok(response);
        } catch (InterruptedException | ExecutionException e) {
            return ResponseEntity.internalServerError()
                .body(new EventResponse("Failed to publish event: " + e.getMessage(), null, -1, -1L, -1L));
        }
    }

    @PostMapping("/publish-async")
    public ResponseEntity<String> publishEventAsync(@RequestBody EventRequest request) {
        ProducerRecord<String, String> record = createProducerRecord(request);
        
        kafkaProducer.send(record, new Callback() {
            @Override
            public void onCompletion(RecordMetadata metadata, Exception exception) {
                if (exception != null) {
                    System.err.println("Error publishing event: " + exception.getMessage());
                } else {
                    System.out.println("Event published to topic: " + metadata.topic() + 
                        ", partition: " + metadata.partition() + 
                        ", offset: " + metadata.offset());
                }
            }
        });
        
        return ResponseEntity.accepted().body("Event accepted for publishing");
    }

    @PostMapping("/publish-batch")
    public ResponseEntity<BatchEventResponse> publishBatchEvents(@RequestBody List<EventRequest> requests) {
        List<String> successfulEvents = new ArrayList<>();
        List<String> failedEvents = new ArrayList<>();
        
        for (EventRequest request : requests) {
            try {
                ProducerRecord<String, String> record = createProducerRecord(request);
                kafkaProducer.send(record).get();
                successfulEvents.add(request.getEventId() != null ? request.getEventId() : "unknown");
            } catch (InterruptedException | ExecutionException e) {
                failedEvents.add(request.getEventId() != null ? request.getEventId() : "unknown");
            }
        }
        
        BatchEventResponse response = new BatchEventResponse(
            successfulEvents.size(),
            failedEvents.size(),
            successfulEvents,
            failedEvents
        );
        
        return ResponseEntity.ok(response);
    }

    private ProducerRecord<String, String> createProducerRecord(EventRequest request) {
        String topic = request.getTopic() != null ? request.getTopic() : "default-events-topic";
        String key = request.getKey();
        String value = request.getMessage();
        
        List<Header> headers = new ArrayList<>();
        
        if (request.getTrackingId() != null) {
            headers.add(new RecordHeader("tracking-id", request.getTrackingId().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getUserId() != null) {
            headers.add(new RecordHeader("user-id", request.getUserId().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getEventId() != null) {
            headers.add(new RecordHeader("event-id", request.getEventId().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getEventType() != null) {
            headers.add(new RecordHeader("event-type", request.getEventType().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getTimestamp() != null) {
            headers.add(new RecordHeader("timestamp", request.getTimestamp().toString().getBytes(StandardCharsets.UTF_8)));
        } else {
            headers.add(new RecordHeader("timestamp", String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getSource() != null) {
            headers.add(new RecordHeader("source", request.getSource().getBytes(StandardCharsets.UTF_8)));
        }
        
        if (request.getCustomHeaders() != null && !request.getCustomHeaders().isEmpty()) {
            for (Map.Entry<String, String> entry : request.getCustomHeaders().entrySet()) {
                if (entry.getValue() != null) {
                    headers.add(new RecordHeader(entry.getKey(), entry.getValue().getBytes(StandardCharsets.UTF_8)));
                }
            }
        }
        
        headers.add(new RecordHeader("content-type", "application/json".getBytes(StandardCharsets.UTF_8)));
        
        ProducerRecord<String, String> record = new ProducerRecord<>(
            topic,
            null,
            key,
            value,
            headers
        );
        
        return record;
    }
}

